// // This module implements a 2-to-1 multiplexer with an enable signal. When EN is high, the output Y takes the value of input B; when EN is low, Y takes the value of input A.
module top_module(
    input A,
    input B,
    input EN,
    output Y
);// Voltage supply signals
    supply1 VPWR;
    supply0 VGND;
    supply1 VPB ;
    supply0 VNA ;

    assign Y = EN ? A : B;

endmodule
